-- ============================================================-- access_control_rules-- Capa configurable de restricci+ฆn de acceso por rol.-- NO sustituye RLS ni los helpers de roles.ts.-- Solo puede RESTRINGIR m+ํs, nunca conceder acceso adicional.-- ============================================================create table if not exists public.access_control_rules (  id bigint generated by default as identity primary key,  empresa_id bigint not null references public.empresas (id) on delete cascade,  role text not null,  resource_type text not null,  resource_key text not null,  action text not null default 'view',  enabled boolean not null default false,  created_at timestamptz not null default timezone('utc'::text, now()),  updated_at timestamptz not null default timezone('utc'::text, now()),  updated_by bigint references public.usuarios (id) on delete set null,  constraint access_control_rules_role_check    check (role in ('Administrador', 'Director', 'Responsable', 'Agente')),  constraint access_control_rules_resource_type_check    check (resource_type in ('page', 'feature', 'action')),  constraint access_control_rules_action_check    check (action in ('view', 'create', 'edit', 'delete', 'use', 'export', 'manage')),  unique (empresa_id, role, resource_key, action));comment on table public.access_control_rules is  'Restricciones configurables de acceso por rol. Capa adicional sobre permisos existentes y RLS.';-- Index para b+ฆsquedas r+ํpidas por empresa + rolcreate index if not exists idx_access_control_rules_lookup  on public.access_control_rules (empresa_id, role, resource_key);-- ิ๖วิ๖ว RLS ิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วิ๖วalter table public.access_control_rules enable row level security;-- SELECT: cualquier usuario autenticado de la misma empresadrop policy if exists access_control_rules_select on public.access_control_rules;create policy access_control_rules_select  on public.access_control_rules  for select  using (    auth.uid() is not null    and empresa_id = public.current_empresa_id()  );-- INSERT: solo Administradordrop policy if exists access_control_rules_insert on public.access_control_rules;create policy access_control_rules_insert  on public.access_control_rules  for insert  with check (    auth.uid() is not null    and empresa_id = public.current_empresa_id()    and public.current_user_role() = 'Administrador'  );-- UPDATE: solo Administradordrop policy if exists access_control_rules_update on public.access_control_rules;create policy access_control_rules_update  on public.access_control_rules  for update  using (    auth.uid() is not null    and empresa_id = public.current_empresa_id()    and public.current_user_role() = 'Administrador'  );-- DELETE: solo Administradordrop policy if exists access_control_rules_delete on public.access_control_rules;create policy access_control_rules_delete  on public.access_control_rules  for delete  using (    auth.uid() is not null    and empresa_id = public.current_empresa_id()    and public.current_user_role() = 'Administrador'  );-- Trigger: actualizar updated_at autom+ํticamentecreate or replace function public.update_access_control_updated_at()returns triggerlanguage plpgsqlsecurity definerset search_path = publicas $$begin  new.updated_at = timezone('utc'::text, now());  return new;end;$$;drop trigger if exists trg_access_control_rules_updated_at on public.access_control_rules;create trigger trg_access_control_rules_updated_at  before update on public.access_control_rules  for each row  execute function public.update_access_control_updated_at();